bad_example:
async def _run_in_executor(self, fn):
    loop = asyncio.get_event_loop()  # DeprecationWarning 3.10, RuntimeError 3.12
    return await loop.run_in_executor(None, fn)

good_example:
async def _run_in_executor(self, fn):
    loop = asyncio.get_running_loop()  # correct: always raises RuntimeError if not inside running loop
    return await loop.run_in_executor(None, fn)
